import { useLingui } from "@lingui/react";
import { Trans } from "@lingui/react/macro";
import { EyeIcon, HeartIcon, DownloadIcon } from "@phosphor-icons/react";
import { motion } from "motion/react";
import type { TemplateMetadata } from "@/dialogs/resume/template/data";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/utils/style";

type TemplateCardProps = {
	id: string;
	metadata: TemplateMetadata;
	onSelect: (templateId: string) => void;
	isFavorite?: boolean;
	onToggleFavorite?: (templateId: string) => void;
};

export function TemplateCard({ 
	id, 
	metadata, 
	onSelect, 
	isFavorite = false, 
	onToggleFavorite 
}: TemplateCardProps) {
	const { i18n } = useLingui();

	return (
		<motion.div
			className="group relative bg-card border rounded-xl overflow-hidden hover:shadow-lg transition-all duration-300"
			whileHover={{ y: -4 }}
		>
			{/* Template Preview */}
			<div className="aspect-[3/4] bg-muted relative overflow-hidden">
				<img
					src={metadata.imageUrl}
					alt={metadata.name}
					className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
					onError={(e) => {
						// Fallback for missing images
						const target = e.target as HTMLImageElement;
						target.src = "/templates/jpg/placeholder.jpg";
					}}
				/>
				
				{/* Overlay Actions */}
				<div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors duration-300 flex items-center justify-center opacity-0 group-hover:opacity-100">
					<div className="flex gap-2">
						<Button
							size="sm"
							variant="secondary"
							onClick={() => onSelect(id)}
							className="bg-white/90 hover:bg-white text-black"
						>
							<EyeIcon size={16} />
							<Trans>Preview</Trans>
						</Button>
						
						{onToggleFavorite && (
							<Button
								size="sm"
								variant="secondary"
								onClick={(e) => {
									e.stopPropagation();
									onToggleFavorite(id);
								}}
								className="bg-white/90 hover:bg-white text-black"
							>
								<HeartIcon 
									size={16} 
									className={cn(isFavorite && "fill-red-500 text-red-500")} 
								/>
							</Button>
						)}
					</div>
				</div>

				{/* Sidebar Position Badge */}
				<div className="absolute top-2 right-2">
					<Badge variant="secondary" className="bg-black/70 text-white text-xs">
						{metadata.sidebarPosition === "left" && "Left Sidebar"}
						{metadata.sidebarPosition === "right" && "Right Sidebar"}
						{metadata.sidebarPosition === "none" && "Single Column"}
					</Badge>
				</div>
			</div>

			{/* Template Info */}
			<div className="p-4 space-y-3">
				<div>
					<h3 className="font-semibold text-lg leading-tight mb-1">{metadata.name}</h3>
					<p className="text-muted-foreground text-sm line-clamp-2">
						{i18n.t(metadata.description)}
					</p>
				</div>

				{/* Tags */}
				{metadata.tags.length > 0 && (
					<div className="flex flex-wrap gap-1">
						{metadata.tags.slice(0, 3).map((tag) => (
							<Badge key={tag} variant="outline" className="text-xs">
								{tag}
							</Badge>
						))}
						{metadata.tags.length > 3 && (
							<Badge variant="outline" className="text-xs">
								+{metadata.tags.length - 3}
							</Badge>
						)}
					</div>
				)}

				{/* Action Buttons */}
				<div className="flex gap-2 pt-2">
					<Button
						onClick={() => onSelect(id)}
						className="flex-1"
						size="sm"
					>
						<Trans>Use Template</Trans>
					</Button>
					
					<Button
						variant="outline"
						size="sm"
						onClick={() => {
							// Download sample PDF
							window.open(`/templates/pdf/${id}.pdf`, '_blank');
						}}
					>
						<DownloadIcon size={16} />
					</Button>
				</div>
			</div>

			{/* Quick Preview on Hover */}
			<div className="absolute bottom-0 left-0 right-0 bg-black/80 text-white p-3 transform translate-y-full group-hover:translate-y-0 transition-transform duration-300">
				<div className="text-sm">
					<div className="font-medium mb-1">Quick Preview</div>
					<div className="text-xs opacity-90 line-clamp-2">
						{i18n.t(metadata.description)}
					</div>
				</div>
			</div>
		</motion.div>
	);
}
